import{_ as t,o as a,c as d,a0 as r}from"./chunks/framework.D7jNN1Sc.js";const u=JSON.parse('{"title":"Material Copier","description":"","frontmatter":{},"headers":[],"relativePath":"features/material-copier.md","filePath":"features/material-copier.md"}'),o={name:"features/material-copier.md"};function c(i,e,l,s,n,p){return a(),d("div",null,[...e[0]||(e[0]=[r('<h1 id="material-copier" tabindex="-1">Material Copier <a class="header-anchor" href="#material-copier" aria-label="Permalink to &quot;Material Copier&quot;">​</a></h1><p>複数選択した GameObject から同名の GameObject へマテリアルをコピー＆ペーストできます。FBX セットアップや衣装のカラーバリエーション対応が一瞬で完了します。MeshRenderer と SkinnedMeshRenderer の両方に対応しています。</p><h2 id="使い方" tabindex="-1">使い方 <a class="header-anchor" href="#使い方" aria-label="Permalink to &quot;使い方&quot;">​</a></h2><ol><li>コピー元の GameObject を選択（複数選択可）→ 右クリック → <code>Copy Materials</code></li><li>コピー先の GameObject を選択 → 右クリック → <code>Paste Materials</code></li></ol><p>マテリアルは名前が一致するオブジェクトに自動で適用されます（例: <code>Head</code> → <code>Head</code>、<code>Body</code> → <code>body</code>）。</p><h2 id="マッチング仕様" tabindex="-1">マッチング仕様 <a class="header-anchor" href="#マッチング仕様" aria-label="Permalink to &quot;マッチング仕様&quot;">​</a></h2><p>コピー元とコピー先のオブジェクトは以下の優先順位で自動対応付けされます。いずれも Renderer を持つオブジェクトのみが対象です。</p><table tabindex="0"><thead><tr><th>優先度</th><th>マッチング方法</th><th>例</th></tr></thead><tbody><tr><td>1</td><td>相対パスの完全一致（ルート名を除く）</td><td><code>Outfit/Jacket</code> → <code>Outfit/Jacket</code></td></tr><tr><td>2</td><td>同じ階層深度での名前一致</td><td><code>Outfit_A/Outer/Accessories/Earing</code>（深度3）→ <code>Outfit_B/Inner/Accessories/Earing</code>（深度3）</td></tr><tr><td>3</td><td>名前一致（深度不問、近い深度を優先）</td><td><code>Outfit/Outer/Jacket</code>（深度3）→ <code>Jacket</code>（深度1）</td></tr><tr><td>4</td><td>大文字小文字を区別しない名前一致</td><td><code>earing</code> → <code>Earing</code></td></tr><tr><td>5</td><td>類似名マッチ（サフィックス除去・共通ベース名）</td><td><code>Ribbon_blue</code> → <code>Ribbon_red</code>、<code>Hair.001</code> → <code>Hair.002</code></td></tr></tbody></table><p>同じ優先度に複数の候補が残る場合は、階層パスの類似度・祖先コンテキストの一致度・深度の近さ・レーベンシュタイン距離の順で選択します。</p><p>このマッチング仕様は MA Material Helper でも共通です。</p><h2 id="アクセス方法" tabindex="-1">アクセス方法 <a class="header-anchor" href="#アクセス方法" aria-label="Permalink to &quot;アクセス方法&quot;">​</a></h2><p>ヒエラルキー右クリック → <code>Kanameliser Editor Plus &gt; Copy Materials / Paste Materials</code></p>',12)])])}const _=t(o,[["render",c]]);export{u as __pageData,_ as default};
